import React, { useRef } from 'react';

export default function BentoGrid({ items }) {
  return (
    <div className="grid md:auto-rows-[20rem] grid-cols-1 md:grid-cols-3 gap-6 max-w-6xl mx-auto py-10 px-4">
      {items.map((item, idx) => {
        const cardRef = useRef(null);

        const handleMouseMove = (e) => {
          if (!cardRef.current) return;
          const rect = cardRef.current.getBoundingClientRect();
          const x = e.clientX - rect.left;
          const y = e.clientY - rect.top;
          cardRef.current.style.setProperty('--mouse-x', `${x}px`);
          cardRef.current.style.setProperty('--mouse-y', `${y}px`);
        };

        return (
          <div
            key={idx}
            ref={cardRef}
            onMouseMove={handleMouseMove}
            className={`relative overflow-hidden group rounded-2xl border border-gray-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-6 flex flex-col justify-between transition-shadow duration-300 hover:shadow-lg ${
              item.className || ""
            }`}
          >
            {/* Spotlight Layer */}
            <div
              className="absolute inset-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-300 -z-10"
              style={{
                background: 'radial-gradient(400px circle at var(--mouse-x, 0px) var(--mouse-y, 0px), rgba(99, 102, 241, 0.08), transparent 80%)'
              }}
            />

            <div className="flex flex-col gap-2">
              {item.icon && <div className="text-indigo-500 w-8 h-8">{item.icon}</div>}
              <h3 className="font-bold text-xl text-gray-800 dark:text-gray-100 mt-2">
                {item.title}
              </h3>
              <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
                {item.description}
              </p>
            </div>

            {item.header && <div className="mt-4 flex-1">{item.header}</div>}
          </div>
        );
      })}
    </div>
  );
}
